// FN_NormalizarPayload — v2.0.0 B.0
// Normaliza input do caller em uma linha de log compatível com obs_logger_v1.
// Fire-and-forget: qualquer erro é absorvido e transformado em linha de log com outcome=error_logger.
try {
  const i = $input.first().json || {};
  const toStr = v => (v === undefined || v === null || v === '') ? null : String(v);
  const toInt = v => {
    if (v === undefined || v === null || v === '') return null;
    const n = parseInt(v, 10);
    return isNaN(n) ? null : n;
  };
  const toNum = v => {
    if (v === undefined || v === null || v === '') return null;
    const n = Number(v);
    return isNaN(n) ? null : n;
  };
  const toJson = v => {
    if (v === undefined || v === null || v === '') return null;
    if (typeof v === 'string') { try { return JSON.parse(v); } catch (_) { return { raw: v }; } }
    return v;
  };

  const stage = toStr(i.stage) || 'unknown';
  const workflow = toStr(i.workflow) || 'unknown';
  const operation = toStr(i.operation) || 'unknown';
  const outcome = toStr(i.outcome) || 'success';

  // Campos opcionais
  const duration_ms = toInt(i.duration_ms);
  const chatid = toStr(i.chatid);
  const messageid = toStr(i.messageid);
  const profissional = toStr(i.profissional);
  const tokens_prompt = toInt(i.tokens_prompt);
  const tokens_output = toInt(i.tokens_output);
  const cost_usd = toNum(i.cost_usd);
  const error_message = toStr(i.error_message);
  const metadata = toJson(i.metadata);

  return [{ json: {
    stage, workflow, operation, outcome,
    duration_ms, chatid, messageid, profissional,
    tokens_prompt, tokens_output, cost_usd, error_message, metadata
  } }];
} catch (err) {
  // Nunca propaga erro — fire-and-forget.
  return [{ json: {
    stage: 'obs.logger',
    workflow: 'obs.logger',
    operation: 'normalize_payload',
    outcome: 'error_logger',
    error_message: String(err && err.message || err),
    metadata: null,
    duration_ms: null, chatid: null, messageid: null, profissional: null,
    tokens_prompt: null, tokens_output: null, cost_usd: null
  } }];
}
